HOST = "0.0.0.0"
PORT = 27015
MAX_DATAGRAM_SIZE = 65507
CHUNK_SIZE = 1200
STATUS_MAGIC = b"GSRV"
QUERY_MAGIC = b"STAT"
PROTOCOL_VERSION = 1


@dataclass
class Player:
    name: str
