class GameServer:
    def __init__(self, host: str = HOST, port: int = PORT):
        self.host = host
        self.port = port
        self.lock = threading.RLock()
        self.running = False
        self.players: List[Player] = []
        self.state = GameState()
        self.socket = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.socket.bind((self.host, self.port))

    def add_player(self, player: Player) -> None:
        with self.lock:
            self.players.append(player)

    def remove_player(self, name: str) -> None:
        with self.lock:
            self.players = [p for p in self.players if p.name != name]

    def build_status_payload(self) -> bytes:
        with self.lock:
            payload = {
                "magic": STATUS_MAGIC.decode("ascii"),
                "protocol": PROTOCOL_VERSION,
                "server": asdict(self.state),
                "uptime_seconds": round(time.time() - self.state.uptime_start, 3),
                "player_count": len(self.players),
                "players": [asdict(p) for p in self.players],
            }
        return json.dumps(payload, separators=(",", ":"), ensure_ascii=False).encode("utf-8")

    def _chunk_payload(self, payload: bytes) -> List[bytes]:
        if len(payload) <= CHUNK_SIZE:
            return [payload]
        chunks = []
        total = (len(payload) + CHUNK_SIZE - 1) // CHUNK_SIZE
        for idx in range(total):
            start = idx * CHUNK_SIZE
            end = min(start + CHUNK_SIZE, len(payload))
            header = struct.pack("!4sHH", STATUS_MAGIC, idx, total)
            chunks.append(header + payload[start:end])
        return chunks

    def _handle_query(self, data: bytes, addr: Tuple[str, int]) -> None:
        if len(data) < len(QUERY_MAGIC) or data[:4] != QUERY_MAGIC:
            return
        payload = self.build_status_payload()
        chunks = self._chunk_payload(payload)
        for chunk in chunks:
            if len(chunk) > MAX_DATAGRAM_SIZE:
                continue
            try:
                self.socket.sendto(chunk, addr)
            except OSError:
                break

    def serve_forever(self) -> None:
        self.running = True
        while self.running:
            try:
                data, addr = self.socket.recvfrom(4096)
                threading.Thread(target=self._handle_query, args=(data, addr), daemon=True).start()
            except OSError:
                if self.running:
                    continue

    def stop(self) -> None:
        self.running = False
        try:
            self.socket.close()
        except OSError:
            pass


